function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'daily');
const expectedFreshnessHours = 36;
const isFresh = (new Date() - new Date(now)) / 3600000 < expectedFreshnessHours;

const lookbackDays = 180;
const end = new Date();
const start = new Date(end);
start.setDate(start.getDate() - lookbackDays);

function formatIsoDate(date) {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
}

function toNumber(value, decimals = 4) {
  if (value === null || value === undefined || value === '') return null;
  const numeric = Number(value);
  if (Number.isNaN(numeric)) return null;
  return Number(numeric.toFixed(decimals));
}

const responseRows = Array.isArray($json.value) ? $json.value : [];
const rows = responseRows
  .map((row) => {
    const dataHoraCotacao = String(row.dataHoraCotacao || '').trim();
    const cotacaoCompra = toNumber(row.cotacaoCompra, 4);
    const cotacaoVenda = toNumber(row.cotacaoVenda, 4);

    return {
      dataHoraCotacao,
      quote_date: dataHoraCotacao ? dataHoraCotacao.slice(0, 10) : null,
      cotacaoCompra,
      cotacaoVenda,
      spread: cotacaoCompra !== null && cotacaoVenda !== null ? Number((cotacaoVenda - cotacaoCompra).toFixed(4)) : null
    };
  })
  .filter((row) => row.dataHoraCotacao && row.cotacaoCompra !== null && row.cotacaoVenda !== null)
  .sort((a, b) => a.dataHoraCotacao.localeCompare(b.dataHoraCotacao));

if (!rows.length) {
  throw new Error('BCB PTAX returned no valid quotes in the selected period');
}

const latest = rows[rows.length - 1];
const previous = rows.length > 1 ? rows[rows.length - 2] : null;
const recentSeries = rows.slice(-10);
const sellValues = rows.map((row) => row.cotacaoVenda).filter((value) => typeof value === 'number');
const minSell = sellValues.length ? Number(Math.min(...sellValues).toFixed(4)) : null;
const maxSell = sellValues.length ? Number(Math.max(...sellValues).toFixed(4)) : null;
const avgSell = sellValues.length ? Number((sellValues.reduce((sum, value) => sum + value, 0) / sellValues.length).toFixed(4)) : null;
const rangeSell = minSell !== null && maxSell !== null ? Number((maxSell - minSell).toFixed(4)) : null;

const changeVsPrevious = previous ? Number((latest.cotacaoVenda - previous.cotacaoVenda).toFixed(4)) : null;
const changePctVsPrevious = previous && previous.cotacaoVenda ? Number((((latest.cotacaoVenda - previous.cotacaoVenda) / previous.cotacaoVenda) * 100).toFixed(4)) : null;

let movementLabel = 'stable';
let summaryEn = `Latest BCB PTAX USD/BRL fixing on ${latest.quote_date} was ${latest.cotacaoVenda.toFixed(4)} BRL sell and ${latest.cotacaoCompra.toFixed(4)} BRL buy.`;
const signals = [
  `Latest PTAX sell ${latest.cotacaoVenda.toFixed(4)} BRL/USD`,
  `Latest PTAX buy ${latest.cotacaoCompra.toFixed(4)} BRL/USD`,
  `10-day sell range ${rangeSell !== null ? rangeSell.toFixed(4) : 'n/a'} BRL`
];

if (changeVsPrevious !== null) {
  if (changeVsPrevious > 0) movementLabel = 'brl_weaker';
  else if (changeVsPrevious < 0) movementLabel = 'brl_stronger';

  summaryEn += ` Versus the previous fixing, the PTAX sell rate changed by ${changeVsPrevious.toFixed(4)} BRL (${changePctVsPrevious.toFixed(4)}%).`;
  if (movementLabel === 'brl_weaker') {
    summaryEn += ' This indicates BRL weakening against the USD versus the previous fixing.';
    signals.push('BRL weakened versus previous PTAX fixing');
  } else if (movementLabel === 'brl_stronger') {
    summaryEn += ' This indicates BRL strengthening against the USD versus the previous fixing.';
    signals.push('BRL strengthened versus previous PTAX fixing');
  } else {
    signals.push('PTAX unchanged versus previous fixing');
  }
}

return [{
  json: {
    source: 'BCB_PTAX',
    source_format: 'odata_json',
    source_url_template: 'https://olinda.bcb.gov.br/olinda/servico/PTAX/versao/v1/odata/CotacaoDolarPeriodo(...)',
    source_url: 'https://olinda.bcb.gov.br/olinda/servico/PTAX/versao/v1/odata/CotacaoDolarPeriodo(...)',
    country: 'BR',
    macroarea: 'prices',
    collected_at: now,
    collected_period: _collectedPeriod,
        is_fresh: isFresh,
    lookback_days: lookbackDays,
    query_start_date: formatIsoDate(start),
    query_end_date: formatIsoDate(end),
    total_quotes: rows.length,
    quote_date: latest.quote_date,
    dataHoraCotacao: latest.dataHoraCotacao,
    cotacaoCompra: latest.cotacaoCompra,
    cotacaoVenda: latest.cotacaoVenda,
    spread: latest.spread,
    movement_label: movementLabel,
    previous_quote_date: previous ? previous.quote_date : null,
    previous_dataHoraCotacao: previous ? previous.dataHoraCotacao : null,
    previous_cotacaoCompra: previous ? previous.cotacaoCompra : null,
    previous_cotacaoVenda: previous ? previous.cotacaoVenda : null,
    change_vs_previous: changeVsPrevious,
    change_pct_vs_previous: changePctVsPrevious,
    sell_stats_lookback: {
      min: minSell,
      avg: avgSell,
      max: maxSell,
      range: rangeSell
    },
    recent_series: recentSeries,
    summary_en: summaryEn,
    signals,
    _chart_fields: ["recent_series"]
  }
}];

const now = new Date().toISOString();
const meta = $('BCB Parse Signals').item.json;

return [{
  json: {
    source: 'BCB_PTAX',
    country: 'BR',
    macroarea: 'prices',
    cadenza: 'daily',
    run_date: now,
    status: 'done',
    completed_at: now,
    quote_date: meta.quote_date || null,
  },
}];

const raw = ($json.text || '').trim();
const cleaned = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```$/i,'').trim();
const parsed = JSON.parse(cleaned);
const base = $('BCB PTAX Parse').item.json;

return [{ json: {
  ...base,
  rule_based_signals: Array.isArray(base.signals) ? base.signals : [],
  rule_based_movement_label: base.movement_label || 'mixed',
  fallback_summary_en: base.summary_en || '',
  movement_label: parsed.movement_label || base.movement_label || 'mixed',
  signals: Array.isArray(parsed.signals) && parsed.signals.length ? parsed.signals : (Array.isArray(base.signals) ? base.signals : []),
  summary_en: parsed.summary_en || base.summary_en || ''
}}];

// Se BCB è down (502/timeout), logga skip e interrompi senza errore
const item = $input.first();
const err = item.json?.error ?? item.error?.message ?? '';
const statusCode = item.json?.statusCode ?? item.json?.status ?? 0;

if (err || statusCode >= 400) {
  // Scrivi direttamente nel log e termina silenziosamente
  return [{
    json: {
      _api_skip: true,
      source: 'BCB_PTAX',
      country: 'BR',
      status: 'skipped_api_error',
      reason: `BCB API unavailable: ${err || 'HTTP ' + statusCode}`,
      run_date: new Date().toISOString(),
      completed_at: new Date().toISOString()
    }
  }];
}
// API OK — passa il dato al Parse
return [{ json: item.json }];
